import java.util.Arrays;
class Solution {
    public void nextPermutation(int[] data) {
        int n = data.length;
        int[] permutations = new int[factorial(n)];
        int index = 0;
        // Generate all permutations
        boolean[] used = new boolean[n];
        generatePermutations(data, used, new int[n], permutations, index);
        // Sort the permutations
        Arrays.sort(permutations);
        // Find the current permutation and return the next one
        for (int i = 0; i < permutations.length; i += n) {
            boolean isCurrent = true;
            for (int j = 0; j < n; j++) {
                if (data[j] != permutations[i + j]) {
                    isCurrent = false;
                    break;
                }
            }
            if (isCurrent) {
                if (i + n < permutations.length) {
                    for (int j = 0; j < n; j++) {
                        data[j] = permutations[i + n + j];
                    }
                }
                else {
                    Arrays.sort(data);
                }
                return;
            }
        }
    }
    private void generatePermutations(int[] data, boolean[] used, int[] current, int[] permutations, int index) {
        if (index == data.length) {
            System.arraycopy(current, 0, permutations, index * data.length, data.length);
            return;
        }
        for (int i = 0; i < data.length; i++) {
            if (!used[i]) {
                used[i] = true;
                current[index] = data[i];
                generatePermutations(data, used, current, permutations, index + 1);
                used[i] = false;
            }
        }
    }
    private int factorial(int n) {
        int result = 1;
        for (int i = 2; i <= n; i++) {
            result *= i;
        }
        return result;
    }
}

