package main

import (
    "fmt"
    "sort"
)

func nextPermutation(data []int) {
    n := len(data)
    if n <= 1 {
        return
    }

    // Generate all permutations
    permutations := [][]int{}
    var generate func([]int, int)
    generate = func(arr []int, start int) {
        if start == len(arr) {
            perm := make([]int, len(arr))
            copy(perm, arr)
            permutations = append(permutations, perm)
            return
        }
        for i := start; i < len(arr); i++ {
            arr[start], arr[i] = arr[i], arr[start]
            generate(arr, start+1)
            arr[start], arr[i] = arr[i], arr[start]
        }
    }
    generate(data, 0)

    // Sort permutations
    sort.Slice(permutations, func(i, j int) bool {
        for k := range permutations[i] {
            if permutations[i][k] != permutations[j][k] {
                return permutations[i][k] < permutations[j][k]
            }
        }
        return false
    })

    // Find the current permutation and return the next one
    for i := 0; i < len(permutations)-1; i++ {
        if equal(permutations[i], data) {
            copy(data, permutations[i+1])
            return
        }
    }
    copy(data, permutations[0])
}

func equal(a, b []int) bool {
    if len(a) != len(b) {
        return false
    }
    for i := range a {
        if a[i] != b[i] {
            return false
        }
    }
    return true
}

func main() {
    data := []int{1, 2, 3}
    nextPermutation(data)
    fmt.Println(data) // Output: [1, 3, 2]
}

