public class Solution {
    public void nextPermutation(int[] data) {
        int n = data.Length;
        List<int> permutations = new List<int>();
        GeneratePermutations(data, 0, n - 1, permutations);
        permutations.Sort();
        int currentIndex = permutations.IndexOf(string.Join(",", data));
        if (currentIndex + 1 < permutations.Count) {
            var nextPermutation = permutations[currentIndex + 1].Split(',').Select(int.Parse).ToArray();
            Array.Copy(nextPermutation, data, n);
        } else {
            Array.Sort(data);
        }
    }

    private void GeneratePermutations(int[] arr, int l, int r, List<int> result) {
        if (l == r) {
            result.Add(string.Join(",", arr));
        } else {
            for (int i = l; i <= r; i++) {
                Swap(arr, l, i);
                GeneratePermutations(arr, l + 1, r, result);
                Swap(arr, l, i); // backtrack
            }
        }
    }

    private void Swap(int[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }
}

