package main

import "fmt"

func nextPermutation(data []int) {
    n := len(data)
    if n <= 1 {
        return
    }

    // Step 1: Find the first decreasing element from the end
    i := n - 2
    for i >= 0 && data[i] >= data[i+1] {
        i--
    }

    if i >= 0 {
        // Step 2: Find the smallest element larger than data[i]
        j := n - 1
        for data[j] <= data[i] {
            j--
        }
        // Swap elements at i and j
        data[i], data[j] = data[j], data[i]
    }

    // Step 3: Reverse the elements after index i
    reverse(data, i+1)
}

func reverse(data []int, start int) {
    end := len(data) - 1
    for start < end {
        data[start], data[end] = data[end], data[start]
        start++
        end--
    }
}

func main() {
    data := []int{1, 2, 3}
    nextPermutation(data)
    fmt.Println(data) // Output: [1, 3, 2]
}

